            <span className="font-bold text-2xl text-keepy-navy tracking-tight">Keepy</span>
          </a>

          {/* Desktop Menu */}
          <div className="hidden md:flex items-center gap-8">
            {navLinks.map((link) => (
              <a
                key={link.name}
                href={link.href}
                className="text-keepy-navy font-medium hover:text-keepy-orange transition-colors"
              >
                {link.name}
              </a>
            ))}
            <a
              href="https://keepy-app.vercel.app"
              target="_blank"
