import React from 'react';
import { motion } from 'framer-motion';

const Bubble = ({ color, size, top, left, delay, duration }: any) => {
  return (
    <motion.div
      className={`absolute rounded-full opacity-40 blur-xl mix-blend-multiply ${color}`}
      style={{
        width: size,
        height: size,
        top: top,
        left: left,
      }}
      animate={{
        y: [0, -40, 0],
        x: [0, 20, 0],
        scale: [1, 1.1, 1],
      }}
      transition={{
        duration: duration,
        repeat: Infinity,
        ease: "easeInOut",
        delay: delay,
      }}
    />
  );
};

export const Bubbles: React.FC = () => {
  // Bubbles configuration
  const bubbles = [
    { color: 'bg-keepy-lime', size: '20rem', top: '-5%', left: '-5%', delay: 0, duration: 10 },
    { color: 'bg-keepy-pink', size: '15rem', top: '10%', left: '80%', delay: 2, duration: 12 },
    { color: 'bg-keepy-cyan', size: '25rem', top: '40%', left: '10%', delay: 4, duration: 15 },
    { color: 'bg-keepy-yellow', size: '18rem', top: '60%', left: '70%', delay: 1, duration: 11 },
    { color: 'bg-keepy-orange', size: '12rem', top: '85%', left: '20%', delay: 3, duration: 9 },
    // More small details
    { color: 'bg-keepy-cyan', size: '5rem', top: '20%', left: '40%', delay: 5, duration: 7 },
    { color: 'bg-keepy-lime', size: '8rem', top: '75%', left: '90%', delay: 0, duration: 8 },
  ];

  return (
    <div className="fixed inset-0 z-0 overflow-hidden pointer-events-none">
      {bubbles.map((b, index) => (
        <Bubble key={index} {...b} />
      ))}
    </div>
  );
};

